{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires analyzing a large set of rules to determine if a specific causal chain exists. I will split this into rule extraction/mapping and logical chain verification.",
  "helpers": [
    {
      "label": "rule_extractor",
      "instructions": "Identify and list all rules from the provided text that involve the butterfly, the fish, or any intermediate entities/actions that could link them. Create a directed graph of these specific rules where an edge exists if one rule's outcome triggers another rule's condition."
    },
    {
      "label": "logic_verifier",
      "instructions": "Using the rule graph provided by the extractor, attempt to find a complete path of triggered rules starting from the butterfly and ending with the fish receiving a secret. If no complete path exists, or if the chain is broken by a missing condition or a contradictory rule, determine if the outcome is definitively false or simply unknown based on the provided rule set."
    }
  ],
  "synthesis_brief": "Combine the extracted rule graph with the logical path analysis. If the logic verifier finds that the rules do not provide enough information to confirm or deny the event, the final answer must be 'unknown'."
}

